diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..ab7bc3a80dfe 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -109,6 +109,41 @@ static Instruction *foldSelectBinOpIdentity(SelectInst &Sel,
   // S = { select (cmp eq X, C),  Y, ? } or { select (cmp ne X, C), ?,  Y }
   return IC.replaceOperand(Sel, IsEq ? 1 : 2, Y);
 }
+/// Fold select c2, (select c1, X, Y), (select c1, Y, X) to select (xor c1, c2), Y, X.
+static Instruction *foldSelectOfSymmetricSelects(SelectInst &Sel,
+                                                 InstCombiner::BuilderTy &Builder) {
+  Value *C2 = Sel.getCondition();
+  Value *TrueVal = Sel.getTrueValue();
+  Value *FalseVal = Sel.getFalseValue();
+
+  Value *C1, *X1, *Y1, *C1_2, *X2, *Y2;
+  if (!match(TrueVal, m_Select(m_Value(C1), m_Value(X1), m_Value(Y1))) ||
+      !match(FalseVal, m_Select(m_Value(C1_2), m_Value(X2), m_Value(Y2))))
+    return nullptr;
+
+  // Both inner selects must have only one use (the outer select) to avoid
+  // increasing instruction count.
+  if (!TrueVal->hasOneUse() || !FalseVal->hasOneUse())
+    return nullptr;
+
+  // Inner conditions must be the same.
+  if (C1 != C1_2)
+    return nullptr;
+
+  // Condition types must match.
+  if (C1->getType() != C2->getType())
+    return nullptr;
+
+  // True/false values must be swapped.
+  if ((X1 == X2 && Y1 == Y2) || (X1 != Y2 || Y1 != X2))
+    return nullptr;
+
+  // Now we have the pattern.
+  Value *X = X1;
+  Value *Y = Y1;
+  Value *Xor = Builder.CreateXor(C1, C2, "xor");
+  return SelectInst::Create(Xor, Y, X);
+}

 /// This folds:
 ///  select (icmp eq (and X, C1)), TC, FC
@@ -3587,6 +3622,8 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {

   if (Instruction *R = foldSelectOfBools(SI))
     return R;
+  if (Instruction *R = foldSelectOfSymmetricSelects(SI, Builder))
+    return R;

   // Selecting between two integer or vector splat integer constants?
   //

log.source_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

log.expect_optimized_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %1 = xor i1 %c1, %c2
  %ret = select i1 %1, i32 %b, i32 %a
  ret i32 %ret
}

